const fs = require('fs');
const path = require('path');

const body = $input.first().json.body || {};
const jobId = body.jobId;
const imageSource = body.imageSource;
const deckName = body.deckName || 'Vocabulary';
const includeAudio = body.includeAudio !== false;
const mode = (body.mode === 'suffix') ? 'suffix' : 'vocabulary';

if (!jobId) {
  throw new Error('Missing jobId');
}

const jobDir = path.join('/var/lib/n8n/jobs', jobId);
const statusFile = path.join(jobDir, 'status.json');

// Select vision prompt based on image type
const visionPrompt = mode === 'suffix'
  ? 'Extract ALL vocabulary words from this suffix/word-ending chart image for Anki flashcards.\n\n'
    + 'This image shows words grouped by their ending pattern (e.g., "-tion: nation, station, motion").\n'
    + 'For each word in the chart, provide:\n'
    + '- word: the exact word as written\n'
    + '- description: a 2-4 word visual description suitable for illustration\n'
    + '  (e.g., for "nation": "country with flag", for "motion": "person moving")\n\n'
    + 'Return ONLY a JSON array - no markdown, no suffix groupings, just individual words:\n'
    + '[{"word": "nation", "description": "country with flag"}, {"word": "station", "description": "train platform"}]'
  : 'Extract ALL vocabulary words from this educational image for Anki flashcards.\n\n'
    + 'For each vocabulary word, provide:\n'
    + '- word: the exact vocabulary word as labeled\n'
    + '- description: 2-4 words describing it (e.g., "red round fruit")\n\n'
    + 'Return ONLY a JSON array - no markdown:\n'
    + '[{"word": "apple", "description": "red round fruit"}]';

// Update status to processing
const status = {
  status: 'extracting',
  phase: 'Extracting vocabulary from image...',
  progress: 0,
  wordCount: null,
  currentWord: null,
  includeAudio,
  mode,
  startedAt: new Date().toISOString()
};
fs.writeFileSync(statusFile, JSON.stringify(status, null, 2));

return [{ json: { jobId, jobDir, statusFile, imageSource, deckName, includeAudio, mode, visionPrompt } }];

const fs = require('fs');
const initData = $('Initialize Job').first().json;
const errorInfo = $input.first().json;

// Parse OpenRouter/API error into a human-readable message
function parseApiError(errorInfo) {
  const raw = errorInfo.error?.message || errorInfo.message || '';
  const statusCode = errorInfo.error?.status || null;

  // Try to extract the inner JSON from pattern: 402 - "{\"error\":{\"message\":\"...\"}}"
  const jsonMatch = raw.match(/^\d+\s*-\s*"(.+)"$/s);
  if (jsonMatch) {
    try {
      const inner = JSON.parse(jsonMatch[1]);
      const msg = inner.error?.message || inner.message || raw;
      return statusCode ? `HTTP ${statusCode}: ${msg}` : msg;
    } catch(e) {}
  }

  // Try direct JSON parse
  try {
    const parsed = JSON.parse(raw);
    return parsed.error?.message || parsed.message || raw;
  } catch(e) {}

  return raw || 'Unknown API error';
}

const errorMsg = parseApiError(errorInfo);

const status = {
  status: 'error',
  phase: 'Vision extraction failed',
  error: errorMsg,
  failedAt: new Date().toISOString()
};
try {
  fs.writeFileSync(initData.statusFile, JSON.stringify(status, null, 2));
} catch (e) { console.error('Failed to write vision error status:', e.message); }

throw new Error('Vision extraction failed: ' + errorMsg);

const fs = require('fs');
const initData = $('Initialize Job').first().json;
const response = $input.first().json;

function safeWriteStatus(file, data) {
  try { fs.writeFileSync(file, JSON.stringify(data, null, 2)); }
  catch (e) { console.error('Status write failed:', e.message); }
}

let content = response.choices?.[0]?.message?.content || '';

if (!content) {
  safeWriteStatus(initData.statusFile, { status: 'error', phase: 'No content from vision API', error: 'Empty response', failedAt: new Date().toISOString() });
  throw new Error('No content in LLM response');
}

let jsonStr = content.trim();
if (jsonStr.includes('```')) {
  const jsonMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) jsonStr = jsonMatch[1].trim();
}
const start = jsonStr.indexOf('[');
const end = jsonStr.lastIndexOf(']') + 1;
if (start >= 0 && end > start) jsonStr = jsonStr.substring(start, end);

let vocabulary;
try {
  vocabulary = JSON.parse(jsonStr);
} catch (e) {
  safeWriteStatus(initData.statusFile, { status: 'error', phase: 'Failed to parse vocabulary', error: e.message, failedAt: new Date().toISOString() });
  throw new Error('Invalid JSON: ' + e.message);
}

if (!Array.isArray(vocabulary) || vocabulary.length === 0) {
  safeWriteStatus(initData.statusFile, { status: 'error', phase: 'No vocabulary found', error: 'Empty vocabulary array', failedAt: new Date().toISOString() });
  throw new Error('No vocabulary found');
}

// Update status with word count
safeWriteStatus(initData.statusFile, {
  status: 'generating',
  phase: 'Generating images...',
  progress: 0,
  wordCount: vocabulary.length,
  currentWord: 0,
  words: vocabulary.map(v => v.word)
});

return vocabulary.map((item, index) => ({
  json: { ...initData, index, word: item.word, description: item.description, totalItems: vocabulary.length }
}));

const fs = require('fs');
const item = $input.first().json;
const initData = $('Initialize Job').first().json;

try {
  const status = JSON.parse(fs.readFileSync(item.statusFile, 'utf-8'));
  status.currentWord = item.index + 1;
  // If audio enabled: images use 0-50%, audio uses 50-100%
  // If audio disabled: images use 0-100%
  const maxProgress = initData.includeAudio ? 50 : 100;
  status.progress = Math.round(((item.index + 1) / item.totalItems) * maxProgress);
  status.phase = `Generating image ${item.index + 1}/${item.totalItems}: ${item.word}`;
  fs.writeFileSync(item.statusFile, JSON.stringify(status, null, 2));
} catch (e) { console.error('Status update failed:', e.message); }

return [{ json: item }];

const crypto = require("crypto");
const fs = require("fs");
const path = require("path");
const item = $input.first().json;

const cacheDir = "/var/lib/n8n/cache";
const cacheKey = crypto.createHash("sha256").update("img-v1:" + item.word + ":" + item.description).digest("hex");
const cacheBin = path.join(cacheDir, cacheKey + ".bin");
const cacheMeta = path.join(cacheDir, cacheKey + ".meta");

if (fs.existsSync(cacheBin) && fs.existsSync(cacheMeta)) {
  const meta = JSON.parse(fs.readFileSync(cacheMeta, "utf-8"));
  const bytes = fs.readFileSync(cacheBin);
  const imgPath = path.join(item.jobDir, "img_" + item.index + ".bin");
  fs.writeFileSync(imgPath, bytes);
  const imageHash = crypto.createHash("sha256").update(bytes).digest("hex");

  try {
    const status = JSON.parse(fs.readFileSync(item.statusFile, "utf-8"));
    status.phase = "Generating image " + (item.index + 1) + "/" + item.totalItems + ": " + item.word + " (cached)";
    fs.writeFileSync(item.statusFile, JSON.stringify(status, null, 2));
  } catch (e) { console.error("Status update failed:", e.message); }

  return [[{ json: { index: item.index, word: item.word, description: item.description, imageFile: imgPath, imageHash, mimeType: meta.mimeType, imageSizeBytes: bytes.length, cacheHit: true } }], []];
} else {
  return [[], [{ json: { ...item, cacheHit: false } }]];
}

// Continue on error - track failed images but don't stop workflow
const prevData = $('Update Progress').first().json;
const { word, description, index } = prevData;
const errorInfo = $input.first().json;

// Parse OpenRouter/API error into a human-readable message
function parseApiError(errorInfo) {
  const raw = errorInfo.error?.message || errorInfo.message || '';
  const statusCode = errorInfo.error?.status || null;

  // Try to extract the inner JSON from pattern: 402 - "{\"error\":{\"message\":\"...\"}}"
  const jsonMatch = raw.match(/^\d+\s*-\s*"(.+)"$/s);
  if (jsonMatch) {
    try {
      const inner = JSON.parse(jsonMatch[1]);
      const msg = inner.error?.message || inner.message || raw;
      return statusCode ? `HTTP ${statusCode}: ${msg}` : msg;
    } catch(e) {}
  }

  // Try direct JSON parse
  try {
    const parsed = JSON.parse(raw);
    return parsed.error?.message || parsed.message || raw;
  } catch(e) {}

  return raw || 'Unknown API error';
}

const errorMsg = parseApiError(errorInfo);
console.error(`Image generation failed for "${word}": ${errorMsg}`);
return [{ json: { index, word, description, error: errorMsg, imageFile: null, imageHash: null } }];

const crypto = require('crypto');
const fs = require('fs');
const path = require('path');
const response = $input.first().json;
const prevData = $('Update Progress').first().json;
const { word, description, index } = prevData;
const jobDir = $('Initialize Job').first().json.jobDir;

try {
  const message = response.choices?.[0]?.message;
  let base64Data = null;

  if (message?.images?.[0]) {
    const img = message.images[0];
    const url = img.image_url?.url || img.url || img;
    if (typeof url === 'string' && url.includes('base64,')) {
      base64Data = url.split('base64,')[1];
    }
  }

  if (!base64Data && message?.content) {
    const m = message.content.match(/data:image\/([^;]+);base64,([A-Za-z0-9+/=]+)/);
    if (m) { base64Data = m[2]; }
  }

  if (!base64Data) throw new Error('No image data in response');

  const bytes = Buffer.from(base64Data, 'base64');

  // Detect actual image format from magic bytes (don't trust URL MIME type)
  let mimeType = 'image/png';
  if (bytes[0] === 0x89 && bytes[1] === 0x50 && bytes[2] === 0x4E && bytes[3] === 0x47) {
    mimeType = 'image/png';
  } else if (bytes[0] === 0xFF && bytes[1] === 0xD8) {
    mimeType = 'image/jpeg';
  } else if (bytes[0] === 0x47 && bytes[1] === 0x49 && bytes[2] === 0x46) {
    mimeType = 'image/gif';
  } else if (bytes[0] === 0x52 && bytes[1] === 0x49 && bytes[2] === 0x46 && bytes[3] === 0x46 && bytes.length > 11 && bytes[8] === 0x57 && bytes[9] === 0x45 && bytes[10] === 0x42 && bytes[11] === 0x50) {
    mimeType = 'image/webp';
  } else {
    const magicHex = bytes.slice(0, 8).toString('hex');
    console.error(`Unknown image format for "${word}": magic bytes ${magicHex}, defaulting to PNG`);
  }

  const hash = crypto.createHash('sha256').update(bytes).digest('hex');

  // Write raw bytes to disk to avoid keeping base64 in memory
  const imgPath = path.join(jobDir, `img_${index}.bin`);
  fs.writeFileSync(imgPath, bytes);

  // Write to cache
  try {
    const cacheDir = "/var/lib/n8n/cache";
    const cacheKey = crypto.createHash("sha256").update("img-v1:" + word + ":" + description).digest("hex");
    fs.writeFileSync(path.join(cacheDir, cacheKey + ".bin"), bytes);
    fs.writeFileSync(path.join(cacheDir, cacheKey + ".meta"), JSON.stringify({ word, description, mimeType, createdAt: new Date().toISOString() }));
  } catch (cacheErr) { console.error("Cache write failed:", cacheErr.message); }

  return [{ json: { index, word, description, imageFile: imgPath, imageHash: hash, mimeType, imageSizeBytes: bytes.length, cacheHit: false } }];
} catch (e) {
  // Continue on error - track failed images but don't stop workflow
  console.error(`Image extraction failed for "${word}": ${e.message}`);
  return [{ json: { index, word, description, error: e.message, imageFile: null, imageHash: null } }];
}

