  const statusCode = errorInfo.error?.status || null;

  // Try to extract the inner JSON from pattern: 402 - "{\"error\":{\"message\":\"...\"}}"
  const jsonMatch = raw.match(/^\d+\s*-\s*"(.+)"$/s);
  if (jsonMatch) {
    try {
