const errorMsg = parseApiError(errorInfo);

const status = {
  status: 'error',
  phase: 'TTS pre-check failed',
  error: 'TTS pre-check failed: ' + errorMsg,
  failedAt: new Date().toISOString()
};
try {
  fs.writeFileSync(initData.statusFile, JSON.stringify(status, null, 2));
} catch (e) { console.error('Failed to write TTS pre-check error status:', e.message); }

throw new Error('TTS pre-check failed: ' + errorMsg);

const fs = require('fs');
const initData = $('Initialize Job').first().json;
const aggregatedData = $('Aggregate All Items').first().json;
const items = aggregatedData.data || [];

try {
  const status = JSON.parse(fs.readFileSync(initData.statusFile, 'utf-8'));
  status.phase = 'Generating pronunciation audio...';
  status.progress = 50;
  status.audioProgress = 0;
  status.audioTotal = items.length;
  fs.writeFileSync(initData.statusFile, JSON.stringify(status, null, 2));
} catch (e) { console.error('Audio status update failed:', e.message); }

// Spread items for TTS loop
return items.map((item, index) => ({
  json: { ...item, audioIndex: index, audioTotal: items.length, statusFile: initData.statusFile }
}));

const fs = require('fs');
const item = $input.first().json;

try {
  const status = JSON.parse(fs.readFileSync(item.statusFile, 'utf-8'));
  status.audioProgress = item.audioIndex + 1;
  status.progress = 50 + Math.round(((item.audioIndex + 1) / item.audioTotal) * 50);
  status.phase = `Generating audio ${item.audioIndex + 1}/${item.audioTotal}: ${item.word}`;
  fs.writeFileSync(item.statusFile, JSON.stringify(status, null, 2));
} catch (e) { console.error('TTS progress update failed:', e.message); }

return [{ json: item }];

const fs = require('fs');
const path = require('path');
const item = $input.first();
if (!item) throw new Error('Extract Audio Data received no input items');
const inputData = item.json || {};
const jobDir = $('Initialize Job').first().json.jobDir;
const index = inputData.index;

// Extract audio from HTTP response - n8n may use any key name for binary data
let audioBase64 = null;
let mimeType = 'audio/mpeg';

if (item.binary) {
  for (const key of Object.keys(item.binary)) {
    const bin = item.binary[key];
    if (bin && bin.data) {
      audioBase64 = bin.data;
      mimeType = bin.mimeType || 'audio/mpeg';
      break;
    }
  }
}

// Write audio bytes to disk to avoid keeping base64 in memory
let audioFile = null;
if (audioBase64) {
  try {
    const bytes = Buffer.from(audioBase64, 'base64');
    audioFile = path.join(jobDir, `audio_${index}.bin`);
    fs.writeFileSync(audioFile, bytes);
  } catch (e) {
    console.error(`Failed to write audio file: ${e.message}`);
    audioFile = null;
  }
}

// Write to cache for future reuse
if (audioFile) {
  try {
    const crypto = require('crypto');
    const cacheDir = '/var/lib/n8n/cache';
    const cacheKey = crypto.createHash('sha256').update('tts-v1:' + inputData.word).digest('hex');
    const cacheBin = path.join(cacheDir, cacheKey + '.bin');
    const cacheMeta = path.join(cacheDir, cacheKey + '.meta');
    fs.copyFileSync(audioFile, cacheBin);
    fs.writeFileSync(cacheMeta, JSON.stringify({
      word: inputData.word,
      mimeType: mimeType,
      createdAt: new Date().toISOString()
    }, null, 2));
  } catch (e) { console.error('Cache write failed:', e.message); }
}

// Update status file - non-fatal, audio extraction can still succeed
if (inputData.statusFile) {
  try {
    const status = JSON.parse(fs.readFileSync(inputData.statusFile, 'utf-8'));
    status.ttsState = audioFile ? 'done' : 'no-data';
    fs.writeFileSync(inputData.statusFile, JSON.stringify(status, null, 2));
  } catch (e) { console.error('TTS status update failed:', e.message); }
}

// Return with audio result - spread preserves context needed by TTS loop
return [{
  json: {
    ...inputData,
    audioFile: audioFile,
    audioMimeType: audioFile ? mimeType : null,
    audioError: audioFile ? null : 'No audio data received',
    cacheHit: false
  }
}];

const fs = require('fs');
const errorInfo = $input.first().json;
const statusFile = errorInfo.statusFile || $('Initialize Job').first().json.statusFile;

// Parse OpenRouter/API error into a human-readable message
function parseApiError(errorInfo) {
  const raw = errorInfo.error?.message || errorInfo.message || '';
  const statusCode = errorInfo.error?.status || null;

  // Try to extract the inner JSON from pattern: 402 - "{\"error\":{\"message\":\"...\"}}"
  const jsonMatch = raw.match(/^\d+\s*-\s*"(.+)"$/s);
  if (jsonMatch) {
    try {
      const inner = JSON.parse(jsonMatch[1]);
      const msg = inner.error?.message || inner.message || raw;
      return statusCode ? `HTTP ${statusCode}: ${msg}` : msg;
    } catch(e) {}
  }

  // Try direct JSON parse
  try {
    const parsed = JSON.parse(raw);
    return parsed.error?.message || parsed.message || raw;
  } catch(e) {}

  return raw || 'Unknown API error';
}

const errorMsg = parseApiError(errorInfo);

const status = { status: 'error', phase: 'TTS generation failed', error: 'TTS failed: ' + errorMsg, failedAt: new Date().toISOString() };
if (statusFile) {
  try {
    fs.writeFileSync(statusFile, JSON.stringify(status, null, 2));
  } catch (e) { console.error('Failed to write error status:', e.message); }
} else {
  console.error('Cannot record TTS error (no statusFile):', errorMsg);
}

throw new Error('TTS failed: ' + errorMsg);

// Pass through items without audio data
const aggregatedData = $input.first().json;
const items = aggregatedData.data || [];

const itemsWithNullAudio = items.map(item => ({
  ...item,
  audioFile: null,
  audioMimeType: null,
  audioError: null
}));

return [{ json: { data: itemsWithNullAudio } }];

const fs = require("fs");
const path = require("path");
const items = ($input.first().json.data || []);
const initData = $("Initialize Job").first().json;

function safeWriteStatus(file, data) {
  try { fs.writeFileSync(file, JSON.stringify(data, null, 2)); }
  catch (e) { console.error("Status write failed:", e.message); }
}

// Update status
try {
  const status = JSON.parse(fs.readFileSync(initData.statusFile, "utf-8"));
  status.phase = "Creating Anki deck...";
  status.progress = 95;
  safeWriteStatus(initData.statusFile, status);
} catch (e) { console.error("Status read failed:", e.message); }

const valid = items.filter(i => i.word && (i.imageFile || i.description));

if (valid.length === 0) {
  safeWriteStatus(initData.statusFile, { status: "error", phase: "No valid cards", error: "No valid items to create deck", failedAt: new Date().toISOString() });
  throw new Error("No valid items");
}

const failedImages = items.filter(i => i.error && !i.imageFile);
const failedImageWords = failedImages.map(i => i.word);
const audioCardCount = valid.filter(i => i.audioFile).length;
const words = valid.map(i => i.word);

// Stream JSON to file one card at a time to avoid holding all base64 in memory
const outputFile = "/tmp/n8n-apkg-input.json";
const fd = fs.openSync(outputFile, "w");
fs.writeSync(fd, JSON.stringify({ deckName: initData.deckName || "Vocabulary" }) .replace(/}$/, ",\"cards\":["));

for (let i = 0; i < valid.length; i++) {
  const item = valid[i];
  let imageBase64 = null;
  if (item.imageFile) {
    try { imageBase64 = fs.readFileSync(item.imageFile).toString("base64"); }
    catch (e) { console.error("Failed to read image " + item.imageFile + ": " + e.message); }
  }
  let audioBase64 = null;
  if (item.audioFile) {
    try { audioBase64 = fs.readFileSync(item.audioFile).toString("base64"); }
    catch (e) { console.error("Failed to read audio " + item.audioFile + ": " + e.message); }
  }
  const card = {
    word: item.word,
    description: item.description || "",
    imageBase64,
    mimeType: item.mimeType || "image/jpeg",
    audioBase64,
    audioMimeType: item.audioMimeType || "audio/mpeg"
  };
  const cardJson = JSON.stringify(card);
  fs.writeSync(fd, (i > 0 ? "," : "") + cardJson);
  // Free memory after each card
  imageBase64 = null;
  audioBase64 = null;
}
fs.writeSync(fd, "]}");
fs.closeSync(fd);

return [{
  json: { ...initData, hasError: false, cardCount: valid.length, imageCardCount: valid.filter(i => i.imageFile).length, audioCardCount, words, failedImageCount: failedImages.length, failedImageWords, inputFile: outputFile }
}];

const fs = require('fs');
const stdout = $input.first().json.stdout || '';
const initData = $('Prepare APKG Input').first().json;

function safeWriteStatus(file, data) {
  try { fs.writeFileSync(file, JSON.stringify(data, null, 2)); }
  catch (e) { console.error('Status write failed:', e.message); }
}

try {
  const output = JSON.parse(stdout);

  if (!output.success) {
    safeWriteStatus(initData.statusFile, { status: 'error', phase: 'APKG generation failed', error: output.error || 'Unknown error', failedAt: new Date().toISOString() });
    throw new Error(output.error);
  }

  // Check if some images failed - show warning
  const failedCount = initData.failedImageCount || 0;
  const hasWarning = failedCount > 0;
  const warningMsg = hasWarning ? `${failedCount} image(s) failed to generate` : null;

  const status = {
    status: hasWarning ? 'partial' : 'complete',
    phase: hasWarning ? `Complete with warnings` : 'Complete!',
    progress: 100,
    wordCount: initData.cardCount,
    imageCardCount: initData.imageCardCount,
    audioCardCount: initData.audioCardCount || 0,
    words: initData.words || [],
    warning: warningMsg,
    failedImageWords: initData.failedImageWords || [],
    deckId: output.deckId,
    downloadUrl: `/webhook/anki-download?id=${output.deckId}`,
    apkgSizeBytes: output.apkgSizeBytes,
    completedAt: new Date().toISOString(),
    deckName: initData.deckName || 'Vocabulary',
    mode: (initData.mode === 'suffix') ? 'suffix' : 'vocabulary'
  };
  safeWriteStatus(initData.statusFile, status);

  return [{ json: { success: true, ...status } }];
} catch (e) {
  if (!e.message.includes('Unknown error')) {
    safeWriteStatus(initData.statusFile, { status: 'error', phase: 'Parse error', error: e.message, failedAt: new Date().toISOString() });
  }
  throw e;
}

const crypto = require("crypto");
const fs = require("fs");
const path = require("path");
const item = $input.first().json;

const cacheDir = "/var/lib/n8n/cache";
const cacheKey = crypto.createHash("sha256").update("tts-v1:" + item.word).digest("hex");
const cacheBin = path.join(cacheDir, cacheKey + ".bin");
const cacheMeta = path.join(cacheDir, cacheKey + ".meta");

if (fs.existsSync(cacheBin) && fs.existsSync(cacheMeta)) {
  const meta = JSON.parse(fs.readFileSync(cacheMeta, "utf-8"));
  const bytes = fs.readFileSync(cacheBin);
  const jobDir = $("Initialize Job").first().json.jobDir;
  const audioPath = path.join(jobDir, "audio_" + item.audioIndex + ".bin");
  fs.writeFileSync(audioPath, bytes);

  try {
    const status = JSON.parse(fs.readFileSync(item.statusFile, "utf-8"));
    status.phase = "Generating audio " + (item.audioIndex + 1) + "/" + item.audioTotal + ": " + item.word + " (cached)";
    fs.writeFileSync(item.statusFile, JSON.stringify(status, null, 2));
  } catch (e) { console.error("Status update failed:", e.message); }

  return [[{ json: { ...item, audioFile: audioPath, audioMimeType: meta.mimeType, audioBase64: null, cacheHit: true } }], []];
} else {
  return [[], [{ json: { ...item, cacheHit: false } }]];
}
